.card {
  position: relative;
  background: #e0e7ff;
  padding: 20px;
  width: 220px;
}
.badge {
  position: absolute;
  top: -10px;
  left: -10px;
  background: #ef4444;
  color: white;
  padding: 3px 10px;
  border-radius: 999px;
  font-size: 12px;
}

.sticky-head {
  position: sticky;
  top: 0;
  background: #6366f1;
  color: white;
  padding: 6px;
}

.sq { position: absolute; width: 90px; height: 90px; }
.z1 { background: #f87171; top: 0;    right: 0;    z-index: 1; }
.z2 { background: #34d399; top: 25px; right: 25px; z-index: 3; }
.z3 { background: #60a5fa; top: 50px; right: 50px; z-index: 2; }
